import type { JsValue } from "@tsonic/core/types.js";

declare global {
  interface String {
    trim(): string;
    join(separator?: string): string;
  }
  interface Number {
    toString(radix?: int): string;
  }
  interface Array<T> {
    readonly length: int;
    push(...items: T[]): int;
    join(separator?: string): string;
  }
  interface Error {
    message: string;
  }
  interface ErrorConstructor {
    readonly prototype: Error;
    new(message?: string): Error;
  }
  interface RangeError extends Error {}
  interface RangeErrorConstructor {
    readonly prototype: RangeError;
    new(message?: string): RangeError;
  }
  interface ArrayConstructor {
    readonly prototype: JsValue[];
    new<T>(...items: T[]): T[];
    of<T>(...items: T[]): T[];
    from(source: string): string[];
    isArray(value: JsValue): value is readonly JsValue[] | JsValue[];
  }
  const Array: ArrayConstructor;
  const Error: ErrorConstructor;
  const RangeError: RangeErrorConstructor;
}

export {};
